using System.Collections.ObjectModel;using CommunityToolkit.Mvvm.ComponentModel;using CommunityToolkit.Mvvm.Input;using GmpCompanyCollector.App.Models;using GmpCompanyCollector.App.Services;
namespace GmpCompanyCollector.App.ViewModels;
public partial class MainViewModel:ObservableObject{public SettingsViewModel Settings{get;} public CollectionViewModel Collection{get;} public DataViewModel Data{get;} public StatisticsViewModel Statistics{get;} public LogViewModel Log{get;} [ObservableProperty] int selectedTabIndex; public Array CollectionKindValues=>Enum.GetValues(typeof(GmpCompanyCollector.App.Models.CollectionKind)); public MainViewModel(){var log=new LogService(); var data=new DataViewModel(); Settings=new(new DataGoApiClient(),new ApiKeyStorageService(),log); Collection=new(new DataGoApiClient(),log,data); Data=data; Statistics=new(data); Log=new(log);}}
public partial class SettingsViewModel(IDataGoApiClient api,ApiKeyStorageService store,LogService log):ObservableObject{[ObservableProperty] string serviceKey=store.Load()??"";[ObservableProperty] bool rememberKey;[ObservableProperty] ServiceKeyMode keyMode=ServiceKeyMode.Auto;[ObservableProperty] string connectionMessage="서비스키를 입력한 뒤 API 연결 테스트를 실행하십시오."; public Array KeyModes=>Enum.GetValues(typeof(ServiceKeyMode)); [RelayCommand] async Task TestAsync(){if(string.IsNullOrWhiteSpace(ServiceKey)){ConnectionMessage="서비스키를 입력하십시오.";return;} try{var sw=System.Diagnostics.Stopwatch.StartNew(); var r=await api.GetCompanyListPageAsync(new(){ServiceKey=ServiceKey,KeyMode=KeyMode,NumOfRows=1},1,CancellationToken.None); sw.Stop(); ConnectionMessage=r.IsSuccess?$"API 연결에 성공했습니다. 전체 검색 결과: {r.Body.TotalCount:N0}건 응답 시간: {sw.Elapsed.TotalSeconds:0.00}초":r.Header.ResultMsg; if(RememberKey)store.Save(ServiceKey); log.Info("API 연결 테스트를 완료했습니다.");}catch(Exception ex){ConnectionMessage="API 연결에 실패했습니다. 서비스키, 인코딩 형식, 인터넷 연결을 확인하십시오. "+ex.Message;log.Error(ConnectionMessage);}} [RelayCommand] void DeleteSavedKey(){store.Delete();ServiceKey="";ConnectionMessage="저장된 인증키를 삭제했습니다.";}}
public partial class CollectionViewModel(IDataGoApiClient api,LogService log,DataViewModel data):ObservableObject{[ObservableProperty] CollectionOptions options=new();[ObservableProperty] CollectionProgress progress=new(){CurrentTask="대기 중"};[ObservableProperty] bool isCollecting; CancellationTokenSource? cts; public int[] RowOptions=>[10,50,100,200,500,999]; [RelayCommand] async Task StartAsync(){if(string.IsNullOrWhiteSpace(Options.ServiceKey)){Progress=new(){CurrentTask="서비스키를 입력하십시오."};return;} cts=new();IsCollecting=true;try{if(Options.Kind!=CollectionKind.FactoryDetailOnly){Progress.CurrentTask="업체 목록을 수집하고 있습니다.";var list=await api.CollectPagesAsync((p,ct)=>api.GetCompanyListPageAsync(Options,p,ct),Options.NumOfRows,new Progress<CollectionProgress>(p=>Progress=p),cts.Token);data.Companies.Clear();foreach(var x in list)data.Companies.Add(x);} if(Options.Kind!=CollectionKind.CompanyListOnly){Progress.CurrentTask="제조소 상세정보를 수집하고 있습니다.";var list=await api.CollectPagesAsync((p,ct)=>api.GetFactoryDetailPageAsync(Options,p,ct),Options.NumOfRows,new Progress<CollectionProgress>(p=>Progress=p),cts.Token);data.Factories.Clear();foreach(var x in list)data.Factories.Add(x);} new StatisticsService().MarkDuplicates(data.Companies,data.Factories);Progress.CurrentTask="데이터 수집이 완료되었습니다.";log.Info("데이터 수집 완료");}catch(OperationCanceledException){Progress.CurrentTask="사용자가 수집을 취소했습니다.";}catch(Exception ex){Progress.CurrentTask="수집 오류: "+ex.Message;log.Error(Progress.CurrentTask);}finally{IsCollecting=false;}} [RelayCommand] void Cancel()=>cts?.Cancel(); [RelayCommand] void Clear(){data.Companies.Clear();data.Factories.Clear();Progress=new(){CurrentTask="결과를 초기화했습니다."};}}
public partial class DataViewModel:ObservableObject{public ObservableCollection<CompanyListItem> Companies{get;}=[]; public ObservableCollection<FactoryDetailItem> Factories{get;}=[]; [ObservableProperty] string searchText=""; [RelayCommand] void SelectAll(){foreach(var x in Companies)x.IsSelected=true;foreach(var x in Factories)x.IsSelected=true;} [RelayCommand] void UnselectAll(){foreach(var x in Companies)x.IsSelected=false;foreach(var x in Factories)x.IsSelected=false;} [RelayCommand] void ExportExcel(){var p=Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.Desktop),$"의약품_업체허가현황_{DateTime.Now:yyyyMMdd_HHmmss}.xlsx");new ExcelExportService().Export(p,Companies,Factories,new StatisticsService().Basic(Companies,Factories));} [RelayCommand] void ExportCsv(){var p=Environment.GetFolderPath(Environment.SpecialFolder.Desktop);new CsvExportService().ExportCompanies(Path.Combine(p,$"의약품_업체목록_{DateTime.Now:yyyyMMdd_HHmmss}.csv"),Companies);}}
public class StatisticsViewModel(DataViewModel data){public DataViewModel Data=>data; public BasicStatistics Basic=>new StatisticsService().Basic(data.Companies,data.Factories);} public class LogViewModel(LogService log){public ObservableCollection<string> Entries=>log.Entries;}
